using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d240a353a0554cd191be4d1640a90575.Client;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the user info
/// persisted by the server during prerendering via PersistentComponentState.
/// This ensures auth state survives the transition from server to WebAssembly.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persisted"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_d240a353a0554cd191be4d1640a90575.Client;

namespace sv_d240a353a0554cd191be4d1640a90575;

/// <summary>
/// Server-side AuthenticationStateProvider that:
///   1. Returns a hardcoded authenticated user (bob@example.com, roles User + Editor).
///   2. Persists the user info into PersistentComponentState so the WASM client
///      can reconstruct the ClaimsPrincipal after the WebAssembly runtime activates.
/// </summary>
public sealed class PersistingServerAuthenticationStateProvider
    : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authStateTask;

    public PersistingServerAuthenticationStateProvider(PersistentComponentState state)
    {
        _state = state;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        _authStateTask ??= BuildAuthenticationStateAsync();
        return _authStateTask;
    }

    private static Task<AuthenticationState> BuildAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "Hardcoded");
        var principal = new ClaimsPrincipal(identity);
        return Task.FromResult(new AuthenticationState(principal));
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated != true)
            return;

        var userInfo = new UserInfo
        {
            Email = principal.FindFirst(ClaimTypes.Email)!.Value,
            Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
        };

        _state.PersistAsJson(nameof(UserInfo), userInfo);
    }

    public void Dispose() => _subscription.Dispose();
}

